  "vajinal-miyom-ameliyati": { slug: "vajinal-miyom-ameliyati", title: "Вагинальная операция на миому", metaTitle: "Вагинальная операция на миому | Доц. Др. Эркан Эльчи", metaDescription: "Информация о вагинальной операции на миому. Лечение субмукозных миом вагинальным доступом.", heroDescription: "Вагинальная операция на миому — это удаление миом, растущих в полость матки (субмукозных), через вагинальный путь.", sections: [{ title: "Что такое вагинальная операция на миому?", content: "Вагинальная операция на миому — это удаление миом, выступающих через шейку матки или выросших в полость матки, через вагинальный путь. Этот метод особенно подходит для субмукозных миом и миом на ножке.\n\nТакже известная как гистероскопическая миомэктомия, при этом методе миомы удаляются с помощью специальных инструментов, введённых через шейку матки. На животе не делается никаких разрезов." }, { title: "Преимущества вагинальной операции", content: "- Нет разреза на животе\n- Короткое время наркоза\n- Выписка в тот же день\n- Очень быстрое восстановление\n- Матка сохраняется\n- Фертильность не нарушается" }], faqs: [{ question: "Могу ли я забеременеть после вагинальной операции на миому?", answer: "Да, вагинальная операция на миому сохраняет матку, и беременность после неё возможна." }], parentSlug: "miyom", parentTitle: "Миома" },

